import{c as t,Q as a,j as o,m as i}from"./chunks/framework.DVP2LVsd.js";const m=JSON.parse('{"title":"Homarr","description":"","frontmatter":{},"headers":[],"relativePath":"api/integrations/homarr.md","filePath":"api/integrations/homarr.md","lastUpdated":1781370958000}'),r={name:"api/integrations/homarr.md"};function s(n,e,d,l,c,h){return a(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="homarr" tabindex="-1">Homarr <a class="header-anchor" href="#homarr" aria-label="Permalink to &quot;Homarr&quot;">​</a></h1><p>LibrisLog can be integrated into <a href="https://homarr.dev/" target="_blank" rel="noreferrer">Homarr</a>, a modern dashboard for your self-hosted services, using its <a href="https://homarr.dev/docs/widgets/iframe/" target="_blank" rel="noreferrer">iframe widget</a>.</p><p>This displays your reading statistics as a self-contained stats card on your Homarr dashboard.</p><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><ul><li>A running LibrisLog instance reachable from your Homarr server</li><li>An <a href="/next/api/integrations/embed-api.html#creating-an-embed-token">embed token</a> with access to the embed widget endpoint</li><li>Embed endpoints must be enabled (default: enabled). See the <a href="/next/api/integrations/embed-api.html">Embed API</a> page for details.</li></ul><h2 id="configuration" tabindex="-1">Configuration <a class="header-anchor" href="#configuration" aria-label="Permalink to &quot;Configuration&quot;">​</a></h2><p>Add an <strong>iframe widget</strong> to your Homarr dashboard:</p><ol><li>In Homarr, navigate to your dashboard, click <strong>Edit</strong> → <strong>Add a tile</strong>.</li><li>Select the <strong>Iframe</strong> widget type.</li><li>Configure the widget with the following URL:</li></ol><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&lt;LIBRISLOG-URL&gt;/embed/v1/stats?token=&lt;EMBED-TOKEN&gt;</span></span></code></pre></div><p>Replace <code>&lt;LIBRISLOG-URL&gt;</code> with your LibrisLog instance URL (e.g. <code>https://librislog.example.com</code>) and <code>&lt;EMBED-TOKEN&gt;</code> with the token you created.</p><h3 id="customizing-the-look" tabindex="-1">Customizing the Look <a class="header-anchor" href="#customizing-the-look" aria-label="Permalink to &quot;Customizing the Look&quot;">​</a></h3><p>See the <a href="/next/api/integrations/embed-api.html#customizing-the-look">Embed API style parameter reference</a> for all available options (<code>theme</code>, <code>accent</code>, <code>radius</code>, <code>density</code>, <code>hide_labels</code>, <code>show</code>, <code>lang</code>, <code>font_scale</code>, <code>layout</code>).</p><p>Example:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&lt;LIBRISLOG-URL&gt;/embed/v1/stats?token=&lt;EMBED-TOKEN&gt;&amp;theme=dark&amp;accent=%23f59e0b&amp;density=compact&amp;hide_labels=true</span></span></code></pre></div><h2 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h2><p><strong>Widget does not appear or is cut off</strong></p><ul><li>Adjust the iframe widget size in Homarr. The widget is responsive and will fit the available space.</li><li>Try <code>density=compact</code> to reduce spacing.</li><li>Try <code>hide_labels=true</code> for a more compact display.</li><li>Use <code>show</code> to display only the stat keys you need.</li></ul><p>For other issues (invalid token, 403 Forbidden, empty stats, CSP errors), see the <a href="/next/api/integrations/embed-api.html#troubleshooting">Embed API troubleshooting</a> guide.</p>',18)])])}const g=t(r,[["render",s]]);export{m as __pageData,g as default};
